@page "/settings"
@rendermode InteractiveServer
@using sv_003dd3da4d66400fb8199c885b432aee.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section == _activeSection ? "active" : "")" @onclick="() => SetActiveSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    <span class="nav-label">@section</span>
                </li>
            }
        </ul>
    </nav>

    <main class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading...</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast @_toastType">
                <span>@_toastMessage</span>
                <button class="toast-close" @onclick="DismissToast">&times;</button>
            </div>
        }
    </main>
</div>

@code {
    private readonly string[] _sections = { "Profile", "Notifications", "Security", "Appearance" };
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private string _toastType = "success";

    // Profile
    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // Notifications
    private NotificationPrefs? _notificationPrefs;
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _allChannels = new() { "general", "marketing", "engineering", "design", "support" };
    private HashSet<string> _mutedChannels = new();

    // Security
    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private string? _revokeSessionId;
    private bool _showRevokeConfirmation;

    // Appearance
    private AppearanceSettings? _appearanceSettings;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;
    private readonly string[] _themes = { "Light", "Dark", "System" };
    private readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData();
    }

    private async Task SetActiveSection(string section)
    {
        _activeSection = section;
        _loading = true;
        await LoadSectionData();
    }

    private async Task LoadSectionData()
    {
        switch (_activeSection)
        {
            case "Profile":
                _profile = await SettingsService.GetProfileAsync();
                _savedProfile = _profile;
                ResetProfileFields();
                break;
            case "Notifications":
                _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                _editEmailNotifications = _notificationPrefs.EmailNotifications;
                _editPushNotifications = _notificationPrefs.PushNotifications;
                _editWeeklyDigest = _notificationPrefs.WeeklyDigest;
                _mutedChannels = new HashSet<string>(_notificationPrefs.MutedChannels);
                break;
            case "Security":
                _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
                _changePasswordExpanded = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "Appearance":
                _appearanceSettings = await SettingsService.GetAppearanceAsync();
                _editTheme = _appearanceSettings.Theme;
                _editFontSize = _appearanceSettings.FontSize;
                _editLanguage = _appearanceSettings.Language;
                _editCompactMode = _appearanceSettings.CompactMode;
                break;
        }
        _loading = false;
    }

    private void ResetProfileFields()
    {
        if (_savedProfile is not null)
        {
            _editDisplayName = _savedProfile.DisplayName;
            _editEmail = _savedProfile.Email;
            _editBio = _savedProfile.Bio;
            _editAvatarUrl = _savedProfile.AvatarUrl;
        }
    }

    // Profile actions
    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _profile = updated;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        ResetProfileFields();
        ShowToast("Changes discarded.", "info");
    }

    // Notifications actions
    private async Task SaveNotificationPrefs()
    {
        var updated = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notificationPrefs = updated;
        ShowToast("Notification preferences saved!", "success");
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    // Security actions
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "error");
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New password and confirmation do not match.", "error");
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Password updated successfully!", "success");
    }

    private void RequestRevokeSession(string sessionId)
    {
        _revokeSessionId = sessionId;
        _showRevokeConfirmation = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_revokeSessionId is not null)
        {
            await SettingsService.RevokeSessionAsync(_revokeSessionId);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked.", "success");
        }
        _showRevokeConfirmation = false;
        _revokeSessionId = null;
    }

    private void CancelRevokeSession()
    {
        _showRevokeConfirmation = false;
        _revokeSessionId = null;
    }

    // Appearance actions
    private async Task SaveAppearance()
    {
        var updated = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearanceSettings = updated;
        ShowToast("Appearance settings saved!", "success");
    }

    // Toast helpers
    private void ShowToast(string message, string type)
    {
        _toastMessage = message;
        _toastType = type;
        _toastVisible = true;
        _ = AutoDismissToast();
    }

    private async Task AutoDismissToast()
    {
        await Task.Delay(3000);
        _toastVisible = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast() => _toastVisible = false;

    private string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    // Render fragments
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h2>Profile Settings</h2>
        <div class="settings-section">
            <div class="avatar-section">
                <div class="avatar-preview">
                    <img src="@_editAvatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url">
                    <label>Avatar URL</label>
                    <input type="text" @bind="_editAvatarUrl" placeholder="https://..." />
                </div>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_editDisplayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_editEmail" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_editBio" rows="4"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h2>Notification Preferences</h2>
        <div class="settings-section">
            <div class="toggle-group">
                <label class="toggle-label">
                    <span>Email Notifications</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_editEmailNotifications" />
                        <span class="slider"></span>
                    </label>
                </label>

                <label class="toggle-label">
                    <span>Push Notifications</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_editPushNotifications" />
                        <span class="slider"></span>
                    </label>
                </label>

                <label class="toggle-label">
                    <span>Weekly Digest</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_editWeeklyDigest" />
                        <span class="slider"></span>
                    </label>
                </label>
            </div>

            <div class="muted-channels">
                <h3>Muted Channels</h3>
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                        <span>#@channel</span>
                    </label>
                }
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveNotificationPrefs">Save Preferences</button>
            </div>
        </div>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h2>Security Settings</h2>
        <div class="settings-section">
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    <span>Change Password</span>
                    <span class="expand-icon">@(_changePasswordExpanded ? "▼" : "▶")</span>
                </button>
                @if (_changePasswordExpanded)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label for="currentPassword">Current Password</label>
                            <input id="currentPassword" type="password" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPassword">New Password</label>
                            <input id="newPassword" type="password" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPassword">Confirm Password</label>
                            <input id="confirmPassword" type="password" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                    </div>
                }
            </div>

            <div class="two-factor-section">
                <label class="toggle-label">
                    <span>Two-Factor Authentication</span>
                    <div class="status-with-toggle">
                        <span class="status-indicator @(_twoFactorEnabled ? "enabled" : "disabled")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        <label class="switch">
                            <input type="checkbox" @bind="_twoFactorEnabled" />
                            <span class="slider"></span>
                        </label>
                    </div>
                </label>
                @if (_securitySettings?.LastPasswordChange is not null)
                {
                    <p class="last-changed">Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</p>
                }
            </div>

            <div class="sessions-section">
                <h3>Active Sessions</h3>
                <table class="sessions-table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_securitySettings?.Sessions is not null)
                        {
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM dd, yyyy HH:mm")</td>
                                    <td>
                                        @if (session.Id != _securitySettings.Sessions.First().Id)
                                        {
                                            <button class="btn btn-danger btn-sm" @onclick="() => RequestRevokeSession(session.Id)">Revoke</button>
                                        }
                                        else
                                        {
                                            <span class="current-session-badge">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

            @if (_showRevokeConfirmation)
            {
                <div class="modal-overlay">
                    <div class="modal-dialog">
                        <h3>Confirm Session Revocation</h3>
                        <p>Are you sure you want to revoke this session? The device will be signed out immediately.</p>
                        <div class="button-group">
                            <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke Session</button>
                            <button class="btn btn-secondary" @onclick="CancelRevokeSession">Cancel</button>
                        </div>
                    </div>
                </div>
            }
        </div>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <h2>Appearance Settings</h2>
        <div class="settings-section">
            <div class="form-group">
                <label>Theme</label>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_editTheme == theme)"
                                   @onchange="() => _editTheme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label>Font Size</label>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_editFontSize == size)"
                                   @onchange="() => _editFontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_editLanguage">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <label class="toggle-label">
                <span>Compact Mode</span>
                <label class="switch">
                    <input type="checkbox" @bind="_editCompactMode" />
                    <span class="slider"></span>
                </label>
            </label>

            <div class="preview-area">
                <h3>Live Preview</h3>
                <div class="preview-box @GetPreviewClasses()">
                    <div class="preview-header">Sample Header</div>
                    <p class="preview-text">This is how your content will look with the selected settings.</p>
                    <button class="preview-button">Sample Button</button>
                </div>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </div>
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"theme-{_editTheme.ToLower()}");
        classes.Add($"font-{_editFontSize.ToLower()}");
        if (_editCompactMode) classes.Add("compact");
        return string.Join(" ", classes);
    }
}

.settings-container {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.08);
    margin: 1rem;
}

/* Sidebar Navigation */
.settings-sidebar {
    width: 220px;
    background: #ffffff;
    border-right: 1px solid #e9ecef;
    padding: 1rem 0;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.875rem 1.5rem;
    cursor: pointer;
    transition: all 0.2s;
    color: #495057;
    font-weight: 500;
    border-left: 3px solid transparent;
}

.settings-nav li:hover {
    background: #f1f3f5;
    color: #212529;
}

.settings-nav li.active {
    background: #e7f5ff;
    color: #1971c2;
    border-left-color: #1971c2;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.2rem;
}

/* Main Content */
.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    background: #ffffff;
}

.settings-content h2 {
    margin: 0 0 1.5rem 0;
    font-size: 1.5rem;
    color: #212529;
}

.settings-section {
    max-width: 700px;
}

.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 200px;
    color: #868e96;
    font-size: 1.1rem;
}

/* Form Elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.5rem;
    font-weight: 500;
    color: #495057;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="password"],
.form-group textarea,
.form-group select {
    width: 100%;
    padding: 0.625rem 0.875rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.2s;
    box-sizing: border-box;
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: #1971c2;
    box-shadow: 0 0 0 3px rgba(25, 113, 194, 0.1);
}

/* Buttons */
.button-group {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn {
    padding: 0.625rem 1.25rem;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.2s;
}

.btn-primary {
    background: #1971c2;
    color: white;
}

.btn-primary:hover {
    background: #1864ab;
}

.btn-secondary {
    background: #e9ecef;
    color: #495057;
}

.btn-secondary:hover {
    background: #dee2e6;
}

.btn-danger {
    background: #e03131;
    color: white;
}

.btn-danger:hover {
    background: #c92a2a;
}

.btn-sm {
    padding: 0.375rem 0.75rem;
    font-size: 0.8rem;
}

/* Avatar Section */
.avatar-section {
    display: flex;
    align-items: center;
    gap: 1.5rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-preview img {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #e9ecef;
}

.avatar-url {
    flex: 1;
}

.avatar-url label {
    display: block;
    margin-bottom: 0.5rem;
    font-weight: 500;
    color: #495057;
}

.avatar-url input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.9rem;
    box-sizing: border-box;
}

/* Toggle Switch */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    margin-bottom: 1.5rem;
}

.toggle-label {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 6px;
}

.switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #ced4da;
    transition: 0.3s;
    border-radius: 26px;
}

.slider:before {
    position: absolute;
    content: "";
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    transition: 0.3s;
    border-radius: 50%;
}

.switch input:checked + .slider {
    background-color: #1971c2;
}

.switch input:checked + .slider:before {
    transform: translateX(22px);
}

/* Muted Channels */
.muted-channels {
    margin-bottom: 1rem;
}

.muted-channels h3 {
    margin: 0 0 0.75rem 0;
    font-size: 1rem;
    color: #495057;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 0.75rem;
    cursor: pointer;
}

.channel-item input[type="checkbox"] {
    width: 18px;
    height: 18px;
    accent-color: #1971c2;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid #e9ecef;
    border-radius: 8px;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
    color: #212529;
    text-align: left;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1.25rem;
    border-top: 1px solid #e9ecef;
}

/* Two-Factor */
.two-factor-section {
    margin-bottom: 1.5rem;
}

.status-with-toggle {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.status-indicator {
    padding: 0.25rem 0.625rem;
    border-radius: 12px;
    font-size: 0.8rem;
    font-weight: 500;
}

.status-indicator.enabled {
    background: #d3f9d8;
    color: #2b8a3e;
}

.status-indicator.disabled {
    background: #ffe3e3;
    color: #c92a2a;
}

.last-changed {
    margin: 0.5rem 0 0 1rem;
    font-size: 0.85rem;
    color: #868e96;
}

/* Sessions Table */
.sessions-section {
    margin-top: 1.5rem;
}

.sessions-section h3 {
    margin: 0 0 1rem 0;
    font-size: 1.1rem;
    color: #212529;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.75rem 1rem;
    text-align: left;
    border-bottom: 1px solid #e9ecef;
}

.sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
    color: #495057;
}

.sessions-table tr:hover {
    background: #f8f9fa;
}

.current-session-badge {
    display: inline-block;
    padding: 0.2rem 0.5rem;
    background: #d3f9d8;
    color: #2b8a3e;
    border-radius: 4px;
    font-size: 0.8rem;
    font-weight: 500;
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
}

.modal-dialog {
    background: white;
    padding: 2rem;
    border-radius: 12px;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
}

.modal-dialog h3 {
    margin: 0 0 0.75rem 0;
    color: #212529;
}

.modal-dialog p {
    color: #495057;
    margin: 0 0 1.5rem 0;
}

/* Radio Group */
.radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.25rem;
}

.radio-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

.radio-label input[type="radio"] {
    accent-color: #1971c2;
}

/* Preview Area */
.preview-area {
    margin-top: 1.5rem;
    margin-bottom: 1rem;
}

.preview-area h3 {
    margin: 0 0 0.75rem 0;
    font-size: 1rem;
    color: #495057;
}

.preview-box {
    padding: 1.5rem;
    border: 1px solid #e9ecef;
    border-radius: 8px;
    transition: all 0.3s;
}

.preview-box.theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-box.theme-dark {
    background: #1a1b1e;
    color: #c1c2c5;
}

.preview-box.theme-system {
    background: #f1f3f5;
    color: #495057;
}

.preview-box.font-small {
    font-size: 0.8rem;
}

.preview-box.font-medium {
    font-size: 1rem;
}

.preview-box.font-large {
    font-size: 1.2rem;
}

.preview-box.compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.preview-header {
    font-weight: 600;
    font-size: 1.2em;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin: 0 0 1rem 0;
    opacity: 0.85;
}

.preview-button {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    background: #1971c2;
    color: white;
    cursor: pointer;
    font-size: 0.9em;
}

.preview-box.theme-dark .preview-button {
    background: #4dabf7;
    color: #1a1b1e;
}

/* Toast */
.toast {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    padding: 1rem 1.5rem;
    border-radius: 8px;
    display: flex;
    align-items: center;
    gap: 1rem;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
    z-index: 2000;
    animation: slideIn 0.3s ease;
}

.toast.success {
    background: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

.toast.error {
    background: #ffe3e3;
    color: #c92a2a;
    border: 1px solid #ffc9c9;
}

.toast.info {
    background: #e7f5ff;
    color: #1971c2;
    border: 1px solid #a5d8ff;
}

.toast-close {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    opacity: 0.7;
    color: inherit;
}

.toast-close:hover {
    opacity: 1;
}

@keyframes slideIn {
    from {
        transform: translateX(100%);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}

