arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_003dd3da4d66400fb8199c885b432aee.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section == _activeSection ? "active" : "")" @onclick="() => SetActiveSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    <span class="nav-label">@section</span>
                </li>
            }
        </ul>
    </nav>

    <main class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading...</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast @_toastType">
                <span>@_toastMessage</span>
                <button class="toast-close" @onclick="DismissToast">&times;</button>
            </div>
        }
    </main>
</div>

@code {
    private readonly string[] _sections = { "Profile", "Notifications", "Security", "Appearance" };
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private string _toastType = "success";

    // Profile
    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // Notifications
    private NotificationPrefs? _notificationPrefs;
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _allChannels = new() { "general", "marketing", "engineering", "design", "support" };
    private HashSet<string> _mutedChannels = new();

    // Security
    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private string? _revokeSessionId;
    private bool _showRevokeConfirmation;

    // Appearance
    private AppearanceSettings? _appearanceSettings;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;
    private readonly string[] _themes = { "Light", "Dark", "System" };
    private readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData();
    }

    private async Task SetActiveSection(string section)
    {
        _activeSection = section;
        _loading = true;
        await LoadSectionData();
    }

    private async Task LoadSectionData()
    {
        switch (_activeSection)
        {
            case "Profile":
                _profile = await SettingsService.GetProfileAsync();
                _savedProfile = _profile;
                ResetProfileFields();
                break;
            case "Notifications":
                _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                _editEmailNotifications = _notificationPrefs.EmailNotifications;
                _editPushNotifications = _notificationPrefs.PushNotifications;
                _editWeeklyDigest = _notificationPrefs.WeeklyDigest;
                _mutedChannels = new HashSet<string>(_notificationPrefs.MutedChannels);
                break;
            case "Security":
                _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
                _changePasswordExpanded = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "Appearance":
                _appearanceSettings = await SettingsService.GetAppearanceAsync();
                _editTheme = _appearanceSettings.Theme;
                _editFontSize = _appearanceSettings.FontSize;
                _editLanguage = _appearanceSettings.Language;
                _editCompactMode = _appearanceSettings.CompactMode;
                break;
        }
        _loading = false;
    }

    private void ResetProfileFields()
    {
        if (_savedProfile is not null)
        {
            _editDisplayName = _savedProfile.DisplayName;
            _editEmail = _savedProfile.Email;
            _editBio = _savedProfile.Bio;
            _editAvatarUrl = _savedProfile.AvatarUrl;
        }
    }

    // Profile actions
    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _profile = updated;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        ResetProfileFields();
        ShowToast("Changes discarded.", "info");
    }

    // Notifications actions
    private async Task SaveNotificationPrefs()
    {
        var updated = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notificationPrefs = updated;
        ShowToast("Notification preferences saved!", "success");
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    // Security actions
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "error");
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New password and confirmation do not match.", "error");
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Password updated successfully!", "success");
    }

    private void RequestRevokeSession(string sessionId)
    {
        _revokeSessionId = sessionId;
        _showRevokeConfirmation = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_revokeSessionId is not null)
        {
            await SettingsService.RevokeSessionAsync(_revokeSessionId);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked.", "success");
        }
        _showRevokeConfirmation = false;
        _revokeSessionId = null;
    }

    private void CancelRevokeSession()
    {
        _showRevokeConfirmation = false;
        _revokeSessionId = null;
    }

    // Appearance actions
    private async Task SaveAppearance()
    {
        var updated = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearanceSettings = updated;
        ShowToast("Appearance settings saved!", "success");
    }

    // Toast helpers
    private void ShowToast(string message, string type)
    {
        _toastMessage = message;
        _toastType = type;
        _toastVisible = true;
        _ = AutoDismissToast();
    }

    private async Task AutoDismissToast()
    {
        await Task.Delay(3000);
        _toastVisible = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast() => _toastVisible = false;

    private string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    // Render fragments
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h2>Profile Settings</h2>
        <div class="settings-section">
            <div class="avatar-section">
                <div class="avatar-preview">
                    <img src="@_editAvatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url">
                    <label>Avatar URL</label>
                    <input type="text" @bind="_editAvatarUrl" placeholder="https://..." />
                </div>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_editDisplayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_editEmail" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_editBio" rows="4"></textarea>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h2>Notification Preferences</h2>
        <div class="settings-section">
            <div class="toggle-group">
                <label class="toggle-label">
                    <span>Email Notifications</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_editEmailNotifications" />
                        <span class="slider"></span>
                    </label>
                </label>

                <label class="toggle-label">
                    <span>Push Notifications</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_editPushNotifications" />
                        <span class="slider"></span>
                    </label>
                </label>

                <label class="toggle-label">
                    <span>Weekly Digest</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_editWeeklyDigest" />
                        <span class="slider"></span>
                    </label>
                </label>
            </div>

            <div class="muted-channels">
                <h3>Muted Channels</h3>
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                        <span>#@channel</span>
                    </label>
                }
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveNotificationPrefs">Save Preferences</button>
            </div>
        </div>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h2>Security Settings</h2>
        <div class="settings-section">
            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    <span>Change Password</span>
                    <span class="expand-icon">@(_changePasswordExpanded ? "▼" : "▶")</span>
                </button>
                @if (_changePasswordExpanded)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label for="currentPassword">Current Password</label>
                            <input id="currentPassword" type="password" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPassword">New Password</label>
                            <input id="newPassword" type="password" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPassword">Confirm Password</label>
                            <input id="confirmPassword" type="password" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-primary" @onclick="ChangePassword">Update Password</button>
                    </div>
                }
            </div>

            <div class="two-factor-section">
                <label class="toggle-label">
                    <span>Two-Factor Authentication</span>
                    <div class="status-with-toggle">
                        <span class="status-indicator @(_twoFactorEnabled ? "enabled" : "disabled")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        <label class="switch">
                            <input type="checkbox" @bind="_twoFactorEnabled" />
                            <span class="slider"></span>
                        </label>
                    </div>
                </label>
                @if (_securitySettings?.LastPasswordChange is not null)
                {
                    <p class="last-changed">Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</p>
                }
            </div>

            <div class="sessions-section">
                <h3>Active Sessions</h3>
                <table class="sessions-table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_securitySettings?.Sessions is not null)
                        {
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM dd, yyyy HH:mm")</td>
                                    <td>
                                        @if (session.Id != _securitySettings.Sessions.First().Id)
                                        {
                                            <button class="btn btn-danger btn-sm" @onclick="() => RequestRevokeSession(session.Id)">Revoke</button>
                                        }
                                        else
                                        {
                                            <span class="current-session-badge">Current</span>
