    z-index: 2000;
    animation: slideIn 0.3s ease;
}

.toast.success {
    background: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

.toast.error {
    background: #ffe3e3;
    color: #c92a2a;
    border: 1px solid #ffc9c9;
}

.toast.info {
    background: #e7f5ff;
    color: #1971c2;
    border: 1px solid #a5d8ff;
}

.toast-close {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    opacity: 0.7;
    color: inherit;
}

.toast-close:hover {
    opacity: 1;
}

@keyframes slideIn {
    from {
        transform: translateX(100%);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}

