{"file_text": "@page "/settings"
@rendermode InteractiveServer
@using sv_003dd3da4d66400fb8199c885b432aee.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section == _activeSection ? "active" : "")" @onclick="() => SetActiveSection(section)">
                    <span class="nav-icon">@GetSectionIcon(section)</span>
                    <span class="nav-label">@section</span>
                </li>
            }
        </ul>
    </nav>

    <main class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading...</div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (_toastVisible)
        {
            <div class="toast @_toastType">
                <span>@_toastMessage</span>
                <button class="toast-close" @onclick="DismissToast">&times;</button>
            </div>
        }
    </main>
</div>

@code {
    private readonly string[] _sections = { "Profile", "Notifications", "Security", "Appearance" };
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private string _toastType = "success";

    // Profile
    private UserProfile? _profile;
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editBio = "";
    private string _editAvatarUrl = "";

    // Notifications
    private NotificationPrefs? _notificationPrefs;
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _allChannels = new() { "general", "marketing", "engineering", "design", "support" };
    private HashSet<string> _mutedChannels = new();

    // Security
    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private string? _revokeSessionId;
    private bool _showRevokeConfirmation;

    // Appearance
    private AppearanceSettings? _appearanceSettings;
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;
    private readonly string[] _themes = { "Light", "Dark", "System" };
    private readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData();
    }

    private async Task SetActiveSection(string section)
    {
        _activeSection = section;
        _loading = true;
        await LoadSectionData();
    }

    private async Task LoadSectionData()
    {
        switch (_activeSection)
        {
            case "Profile":
                _profile = await SettingsService.GetProfileAsync();
                _savedProfile = _profile;
                ResetProfileFields();
                break;
            case "Notifications":
                _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();
                _editEmailNotifications = _notificationPrefs.EmailNotifications;
                _editPushNotifications = _notificationPrefs.PushNotifications;
                _editWeeklyDigest = _notificationPrefs.WeeklyDigest;
                _mutedChannels = new HashSet<string>(_notificationPrefs.MutedChannels);
                break;
            case "Security":
                _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _securitySettings.TwoFactorEnabled;
                _changePasswordExpanded = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                break;
            case "Appearance":
                _appearanceSettings = await SettingsService.GetAppearanceAsync();
                _editTheme = _appearanceSettings.Theme;
                _editFontSize = _appearanceSettings.FontSize;
                _editLanguage = _appearanceSettings.Language;
                _editCompactMode = _appearanceSettings.CompactMode;
                break;
        }
        _loading = false;
    }

    private void ResetProfileFields()
    {
        if (_savedProfile is not null)
        {
            _editDisplayName = _savedProfile.DisplayName;
            _editEmail = _savedProfile.Email;
            _editBio = _savedProfile.Bio;
            _editAvatarUrl = _savedProfile.AvatarUrl;
        }
    }

    // Profile actions
    private async Task SaveProfile()
    {
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _profile = updated;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        ResetProfileFields();
        ShowToast("Changes discarded.", "info");
    }

    // Notifications actions
    private async Task SaveNotificationPrefs()
    {
        var updated = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _notificationPrefs = updated;
        ShowToast("Notification preferences saved!", "success");
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    // Security actions
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "error");
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New password and confirmation do not match.", "error");
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Password updated successfully!", "success");
    }

    private void RequestRevokeSession(string sessionId)
    {
        _revokeSessionId = sessionId;
        _showRevokeConfirmation = true;
