    private async Task ConfirmRevokeSession()
    {
        if (_revokeSessionId is not null)
        {
            await SettingsService.RevokeSessionAsync(_revokeSessionId);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked.", "success");
        }
        _showRevokeConfirmation = false;
        _revokeSessionId = null;
    }

    private void CancelRevokeSession()
    {
        _showRevokeConfirmation = false;
        _revokeSessionId = null;
    }

    // Appearance actions
    private async Task SaveAppearance()
    {
        var updated = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _appearanceSettings = updated;
        ShowToast("Appearance settings saved!", "success");
    }

    // Toast helpers
    private void ShowToast(string message, string type)
    {
        _toastMessage = message;
        _toastType = type;
        _toastVisible = true;
        _ = AutoDismissToast();
    }

    private async Task AutoDismissToast()
    {
        await Task.Delay(3000);
        _toastVisible = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast() => _toastVisible = false;

    private string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    // Render fragments
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h2>Profile Settings</h2>
        <div class="settings-section">
            <div class="avatar-section">
                <div class="avatar-preview">
                    <img src="@_editAvatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url">
