    display: block;
    margin-bottom: 0.5rem;
    font-weight: 500;
    color: #495057;
}

.avatar-url input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.9rem;
    box-sizing: border-box;
}

/* Toggle Switch */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    margin-bottom: 1.5rem;
}

.toggle-label {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 6px;
}

.switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
}

.switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: #ced4da;
    transition: 0.3s;
    border-radius: 26px;
}

.slider:before {
    position: absolute;
    content: "";
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background-color: white;
    transition: 0.3s;
    border-radius: 50%;
}

.switch input:checked + .slider {
    background-color: #1971c2;
}

.switch input:checked + .slider:before {
    transform: translateX(22px);
}

/* Muted Channels */
.muted-channels {
    margin-bottom: 1rem;
}

.muted-channels h3 {
    margin: 0 0 0.75rem 0;
    font-size: 1rem;
    color: #495057;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 0.75rem;
    cursor: pointer;
}

.channel-item input[type="checkbox"] {
    width: 18px;
    height: 18px;
    accent-color: #1971c2;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid #e9ecef;
    border-radius: 8px;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
    color: #212529;
    text-align: left;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1.25rem;
    border-top: 1px solid #e9ecef;
}

