.two-factor-section {
    margin-bottom: 1.5rem;
}

.status-with-toggle {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.status-indicator {
    padding: 0.25rem 0.625rem;
    border-radius: 12px;
    font-size: 0.8rem;
    font-weight: 500;
}

.status-indicator.enabled {
    background: #d3f9d8;
    color: #2b8a3e;
}

.status-indicator.disabled {
    background: #ffe3e3;
    color: #c92a2a;
}

.last-changed {
    margin: 0.5rem 0 0 1rem;
    font-size: 0.85rem;
    color: #868e96;
}

/* Sessions Table */
.sessions-section {
    margin-top: 1.5rem;
}

.sessions-section h3 {
    margin: 0 0 1rem 0;
    font-size: 1.1rem;
    color: #212529;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.75rem 1rem;
    text-align: left;
    border-bottom: 1px solid #e9ecef;
}

.sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
    color: #495057;
}

.sessions-table tr:hover {
    background: #f8f9fa;
}

.current-session-badge {
    display: inline-block;
    padding: 0.2rem 0.5rem;
    background: #d3f9d8;
    color: #2b8a3e;
    border-radius: 4px;
    font-size: 0.8rem;
    font-weight: 500;
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
}

.modal-dialog {
    background: white;
    padding: 2rem;
    border-radius: 12px;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
}

.modal-dialog h3 {
    margin: 0 0 0.75rem 0;
    color: #212529;
}

.modal-dialog p {
    color: #495057;
    margin: 0 0 1.5rem 0;
}

/* Radio Group */
.radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.25rem;
}

.radio-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

.radio-label input[type="radio"] {
    accent-color: #1971c2;
}

/* Preview Area */
.preview-area {
    margin-top: 1.5rem;
    margin-bottom: 1rem;
}

.preview-area h3 {
    margin: 0 0 0.75rem 0;
    font-size: 1rem;
    color: #495057;
}

.preview-box {
    padding: 1.5rem;
    border: 1px solid #e9ecef;
    border-radius: 8px;
    transition: all 0.3s;
}

.preview-box.theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-box.theme-dark {
    background: #1a1b1e;
    color: #c1c2c5;
}

.preview-box.theme-system {
    background: #f1f3f5;
    color: #495057;
}

.preview-box.font-small {
    font-size: 0.8rem;
}

.preview-box.font-medium {
    font-size: 1rem;
}

.preview-box.font-large {
    font-size: 1.2rem;
}

.preview-box.compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.preview-header {
    font-weight: 600;
    font-size: 1.2em;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin: 0 0 1rem 0;
    opacity: 0.85;
}

.preview-button {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    background: #1971c2;
    color: white;
    cursor: pointer;
    font-size: 0.9em;
}

.preview-box.theme-dark .preview-button {
    background: #4dabf7;
    color: #1a1b1e;
}

/* Toast */
.toast {
    position: fixed;
    bottom: 2rem;
    right: 2rem;
    padding: 1rem 1.5rem;
    border-radius: 8px;
    display: flex;
    align-items: center;
    gap: 1rem;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
    z-index: 2000;
    animation: slideIn 0.3s ease;
}

.toast.success {
    background: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

.toast.error {
    background: #ffe3e3;
    color: #c92a2a;
    border: 1px solid #ffc9c9;
}

.toast.info {
    background: #e7f5ff;
    color: #1971c2;
    border: 1px solid #a5d8ff;
}

.toast-close {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    opacity: 0.7;
    color: inherit;
}

.toast-close:hover {
    opacity: 1;
}

@keyframes slideIn {
    from {
        transform: translateX(100%);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}
