.muted-channels h3 {
    margin: 0 0 0.75rem 0;
    font-size: 1rem;
    color: #495057;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 0.75rem;
    cursor: pointer;
}

.channel-item input[type="checkbox"] {
    width: 18px;
    height: 18px;
    accent-color: #1971c2;
}

