+    margin: 1rem;
+}
+
+/* Sidebar Navigation */
+.settings-sidebar {
+    width: 220px;
+    background: #ffffff;
+    border-right: 1px solid #e9ecef;
+    padding: 1rem 0;
+}
+
+.settings-nav {
+    list-style: none;
+    padding: 0;
+    margin: 0;
+}
+
+.settings-nav li {
+    display: flex;
+    align-items: center;
+    gap: 0.75rem;
+    padding: 0.875rem 1.5rem;
+    cursor: pointer;
+    transition: all 0.2s;
+    color: #495057;
+    font-weight: 500;
+    border-left: 3px solid transparent;
+}
+
+.settings-nav li:hover {
+    background: #f1f3f5;
+    color: #212529;
+}
+
+.settings-nav li.active {
+    background: #e7f5ff;
+    color: #1971c2;
+    border-left-color: #1971c2;
+    font-weight: 600;
+}
+
+.nav-icon {
+    font-size: 1.2rem;
+}
+
+/* Main Content */
+.settings-content {
+    flex: 1;
+    padding: 2rem;
+    position: relative;
+    background: #ffffff;
+}
+
+.settings-content h2 {
+    margin: 0 0 1.5rem 0;
+    font-size: 1.5rem;
+    color: #212529;
+}
+
+.settings-section {
+    max-width: 700px;
+}
+
+.loading-spinner {
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    height: 200px;
+    color: #868e96;
+    font-size: 1.1rem;
+}
+
+/* Form Elements */
+.form-group {
+    margin-bottom: 1.25rem;
+}
+
+.form-group label {
+    display: block;
+    margin-bottom: 0.5rem;
+    font-weight: 500;
+    color: #495057;
+}
+
+.form-group input[type="text"],
+.form-group input[type="email"],
+.form-group input[type="password"],
+.form-group textarea,
+.form-group select {
+    width: 100%;
+    padding: 0.625rem 0.875rem;
+    border: 1px solid #ced4da;
+    border-radius: 6px;
+    font-size: 0.95rem;
+    transition: border-color 0.2s;
+    box-sizing: border-box;
+}
+
+.form-group input:focus,
+.form-group textarea:focus,
+.form-group select:focus {
+    outline: none;
+    border-color: #1971c2;
+    box-shadow: 0 0 0 3px rgba(25, 113, 194, 0.1);
+}
+
+/* Buttons */
+.button-group {
+    display: flex;
+    gap: 0.75rem;
+    margin-top: 1.5rem;
+}
+
+.btn {
+    padding: 0.625rem 1.25rem;
+    border: none;
+    border-radius: 6px;
+    font-size: 0.9rem;
+    font-weight: 500;
+    cursor: pointer;
+    transition: all 0.2s;
+}
+
+.btn-primary {
+    background: #1971c2;
+    color: white;
+}
+
+.btn-primary:hover {
+    background: #1864ab;
+}
+
+.btn-secondary {
+    background: #e9ecef;
+    color: #495057;
+}
+
+.btn-secondary:hover {
+    background: #dee2e6;
+}
+
+.btn-danger {
+    background: #e03131;
+    color: white;
+}
+
+.btn-danger:hover {
+    background: #c92a2a;
+}
+
+.btn-sm {
+    padding: 0.375rem 0.75rem;
+    font-size: 0.8rem;
+}
+
+/* Avatar Section */
+.avatar-section {
+    display: flex;
+    align-items: center;
+    gap: 1.5rem;
+    margin-bottom: 1.5rem;
+    padding: 1rem;
+    background: #f8f9fa;
+    border-radius: 8px;
+}
+
+.avatar-preview img {
+    width: 80px;
+    height: 80px;
+    border-radius: 50%;
+    object-fit: cover;
+    border: 3px solid #e9ecef;
+}
+
+.avatar-url {
+    flex: 1;
+}
+
+.avatar-url label {
+    display: block;
+    margin-bottom: 0.5rem;
+    font-weight: 500;
+    color: #495057;
+}
+
+.avatar-url input {
+    width: 100%;
+    padding: 0.5rem 0.75rem;
+    border: 1px solid #ced4da;
+    border-radius: 6px;
+    font-size: 0.9rem;
+    box-sizing: border-box;
+}
+
+/* Toggle Switch */
+.toggle-group {
+    display: flex;
+    flex-direction: column;
+    gap: 1rem;
+    margin-bottom: 1.5rem;
+}
+
+.toggle-label {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 0.75rem 1rem;
+    background: #f8f9fa;
+    border-radius: 6px;
+}
+
+.switch {
+    position: relative;
+    display: inline-block;
+    width: 48px;
+    height: 26px;
+}
+
+.switch input {
+    opacity: 0;
+    width: 0;
+    height: 0;
+}
+
+.slider {
+    position: absolute;
+    cursor: pointer;
+    top: 0;
+    left: 0;
+    right: 0;
+    bottom: 0;
+    background-color: #ced4da;
+    transition: 0.3s;
+    border-radius: 26px;
+}
+
+.slider:before {
+    position: absolute;
+    content: "";
+    height: 20px;
+    width: 20px;
+    left: 3px;
+    bottom: 3px;
+    background-color: white;
+    transition: 0.3s;
+    border-radius: 50%;
+}
+
+.switch input:checked + .slider {
+    background-color: #1971c2;
+}
+
+.switch input:checked + .slider:before {
+    transform: translateX(22px);
+}
+
+/* Muted Channels */
+.muted-channels {
+    margin-bottom: 1rem;
+}
+
+.muted-channels h3 {
+    margin: 0 0 0.75rem 0;
+    font-size: 1rem;
+    color: #495057;
+}
+
+.channel-item {
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+    padding: 0.5rem 0.75rem;
+    cursor: pointer;
+}
+
+.channel-item input[type="checkbox"] {
+    width: 18px;
+    height: 18px;
+    accent-color: #1971c2;
+}
+
+/* Expandable Panel */
+.expandable-panel {
+    border: 1px solid #e9ecef;
+    border-radius: 8px;
+    margin-bottom: 1.5rem;
+    overflow: hidden;
+}
+
+.panel-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    width: 100%;
+    padding: 1rem 1.25rem;
+    background: #f8f9fa;
+    border: none;
+    cursor: pointer;
+    font-size: 1rem;
+    font-weight: 500;
+    color: #212529;
+    text-align: left;
+}
+
+.panel-header:hover {
+    background: #e9ecef;
+}
+
+.panel-body {
+    padding: 1.25rem;
+    border-top: 1px solid #e9ecef;
+}
+
+/* Two-Factor */
+.two-factor-section {
+    margin-bottom: 1.5rem;
+}
+
+.status-with-toggle {
+    display: flex;
+    align-items: center;
+    gap: 0.75rem;
+}
+
+.status-indicator {
+    padding: 0.25rem 0.625rem;
+    border-radius: 12px;
+    font-size: 0.8rem;
+    font-weight: 500;
+}
+
+.status-indicator.enabled {
+    background: #d3f9d8;
+    color: #2b8a3e;
+}
+
+.status-indicator.disabled {
+    background: #ffe3e3;
+    color: #c92a2a;
+}
+
+.last-changed {
+    margin: 0.5rem 0 0 1rem;
+    font-size: 0.85rem;
+    color: #868e96;
+}
+
+/* Sessions Table */
+.sessions-section {
+    margin-top: 1.5rem;
+}
+
+.sessions-section h3 {
+    margin: 0 0 1rem 0;
+    font-size: 1.1rem;
+    color: #212529;
+}
+
+.sessions-table {
+    width: 100%;
+    border-collapse: collapse;
+    font-size: 0.9rem;
+}
+
+.sessions-table th,
+.sessions-table td {
+    padding: 0.75rem 1rem;
+    text-align: left;
+    border-bottom: 1px solid #e9ecef;
+}
+
+.sessions-table th {
+    background: #f8f9fa;
+    font-weight: 600;
+    color: #495057;
+}
+
+.sessions-table tr:hover {
+    background: #f8f9fa;
+}
+
+.current-session-badge {
+    display: inline-block;
+    padding: 0.2rem 0.5rem;
+    background: #d3f9d8;
+    color: #2b8a3e;
+    border-radius: 4px;
+    font-size: 0.8rem;
+    font-weight: 500;
+}
+
+/* Modal */
+.modal-overlay {
+    position: fixed;
+    top: 0;
+    left: 0;
+    right: 0;
+    bottom: 0;
+    background: rgba(0, 0, 0, 0.5);
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    z-index: 1000;
+}
+
+.modal-dialog {
+    background: white;
+    padding: 2rem;
+    border-radius: 12px;
+    max-width: 420px;
+    width: 90%;
+    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
+}
+
+.modal-dialog h3 {
+    margin: 0 0 0.75rem 0;
+    color: #212529;
+}
+
+.modal-dialog p {
+    color: #495057;
+    margin: 0 0 1.5rem 0;
+}
+
+/* Radio Group */
+.radio-group {
+    display: flex;
+    gap: 1.5rem;
+    margin-top: 0.25rem;
+}
+
+.radio-label {
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+    cursor: pointer;
+}
+
+.radio-label input[type="radio"] {
+    accent-color: #1971c2;
+}
+
+/* Preview Area */
+.preview-area {
+    margin-top: 1.5rem;
+    margin-bottom: 1rem;
+}
+
+.preview-area h3 {
+    margin: 0 0 0.75rem 0;
+    font-size: 1rem;
+    color: #495057;
+}
+
+.preview-box {
+    padding: 1.5rem;
+    border: 1px solid #e9ecef;
+    border-radius: 8px;
+    transition: all 0.3s;
+}
+
+.preview-box.theme-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-box.theme-dark {
+    background: #1a1b1e;
+    color: #c1c2c5;
+}
+
+.preview-box.theme-system {
+    background: #f1f3f5;
+    color: #495057;
+}
+
+.preview-box.font-small {
+    font-size: 0.8rem;
+}
+
+.preview-box.font-medium {
+    font-size: 1rem;
+}
+
+.preview-box.font-large {
+    font-size: 1.2rem;
+}
+
+.preview-box.compact {
+    padding: 0.75rem;
+    line-height: 1.3;
+}
+
+.preview-header {
+    font-weight: 600;
+    font-size: 1.2em;
+    margin-bottom: 0.5rem;
+}
+
+.preview-text {
+    margin: 0 0 1rem 0;
+    opacity: 0.85;
+}
+
+.preview-button {
+    padding: 0.5rem 1rem;
+    border: none;
+    border-radius: 4px;
+    background: #1971c2;
+    color: white;
+    cursor: pointer;
+    font-size: 0.9em;
+}
+
+.preview-box.theme-dark .preview-button {
+    background: #4dabf7;
+    color: #1a1b1e;
+}
+
+/* Toast */
+.toast {
+    position: fixed;
+    bottom: 2rem;
+    right: 2rem;
+    padding: 1rem 1.5rem;
+    border-radius: 8px;
+    display: flex;
+    align-items: center;
+    gap: 1rem;
+    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
+    z-index: 2000;
+    animation: slideIn 0.3s ease;
+}
+
+.toast.success {
+    background: #d3f9d8;
+    color: #2b8a3e;
+    border: 1px solid #b2f2bb;
+}
+
+.toast.error {
+    background: #ffe3e3;
+    color: #c92a2a;
+    border: 1px solid #ffc9c9;
+}
+
+.toast.info {
+    background: #e7f5ff;
+    color: #1971c2;
+    border: 1px solid #a5d8ff;
+}
+
+.toast-close {
+    background: none;
+    border: none;
+    font-size: 1.2rem;
+    cursor: pointer;
+    opacity: 0.7;
+    color: inherit;
+}
+
+.toast-close:hover {
+    opacity: 1;
+}
+
+@keyframes slideIn {
+    from {
+        transform: translateX(100%);
+        opacity: 0;
+    }
+    to {
+        transform: translateX(0);
+        opacity: 1;
+    }
+}
+

