                            <th>Location</th>
                            <th>Last Active</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_securitySettings?.Sessions is not null)
                        {
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM dd, yyyy HH:mm")</td>
                                    <td>
                                        @if (session.Id != _securitySettings.Sessions.First().Id)
                                        {
                                            <button class="btn btn-danger btn-sm" @onclick="() => RequestRevokeSession(session.Id)">Revoke</button>
                                        }
                                        else
                                        {
                                            <span class="current-session-badge">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

