                                   checked="@(_editTheme == theme)"
                                   @onchange="() => _editTheme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label>Font Size</label>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_editFontSize == size)"
                                   @onchange="() => _editFontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_editLanguage">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <label class="toggle-label">
                <span>Compact Mode</span>
                <label class="switch">
                    <input type="checkbox" @bind="_editCompactMode" />
                    <span class="slider"></span>
                </label>
            </label>

            <div class="preview-area">
                <h3>Live Preview</h3>
                <div class="preview-box @GetPreviewClasses()">
                    <div class="preview-header">Sample Header</div>
                    <p class="preview-text">This is how your content will look with the selected settings.</p>
                    <button class="preview-button">Sample Button</button>
                </div>
            </div>

            <div class="button-group">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </div>
    };

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"theme-{_editTheme.ToLower()}");
        classes.Add($"font-{_editFontSize.ToLower()}");
        if (_editCompactMode) classes.Add("compact");
        return string.Join(" ", classes);
    }
}

